#include "voltage_divider.h"
#include <Arduino.h>
#define VDIV_PIN 35
static float _r1=30000,_r2=7500,_v=0;static unsigned long _l=0;
void vdiv_setup(float r1,float r2){_r1=r1;_r2=r2;analogReadResolution(12);Serial.println("[vdiv] OK");}
void vdiv_loop(){if(millis()-_l<1000)return;_l=millis();int r=0;for(int i=0;i<10;i++)r+=analogRead(VDIV_PIN);r/=10;_v=(r*3.3/4095.0)*((_r1+_r2)/_r2);}
float vdiv_get_voltage(){return _v;}
